const amqp = require('amqplib');
const { Pool } = require('pg');
const crypto = require('crypto');
const { exec } = require('child_process');
const util = require('util');

const execPromise = util.promisify(exec);

// Database connection pool
const pool = new Pool({
  user: process.env.DB_USER || 'postgres',
  host: process.env.DB_HOST || 'localhost',
  database: process.env.DB_NAME || 'eventdb',
  password: process.env.DB_PASSWORD || 'password',
  port: process.env.DB_PORT || 5432,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

// RabbitMQ connection
const rabbitmqUrl = process.env.RABBITMQ_URL || 'amqp://localhost';
let connection;
let channel;

// Message validation
const validateMessage = (message) => {
  if (!message || typeof message !== 'object') {
    throw new Error('Invalid message format');
  }
  
  if (!message.type || typeof message.type !== 'string') {
    throw new Error('Message type is required');
  }
  
  if (!message.id || typeof message.id !== 'string') {
    throw new Error('Message ID is required');
  }
  
  return true;
};

// Secure message processing
const processMessage = async (message) => {
  try {
    const parsedMessage = JSON.parse(message.content.toString());
    validateMessage(parsedMessage);
    
    const { type, payload, id } = parsedMessage;
    
    // Log message ID for tracking
    console.log(`Processing message ID: ${id}, Type: ${type}`);
    
    switch (type) {
      case 'DATABASE_QUERY':
        return await handleDatabaseQuery(payload);
      case 'SYSTEM_COMMAND':
        return await handleSystemCommand(payload);
      case 'DATA_PROCESSING':
        return await handleDataProcessing(payload);
      default:
        throw new Error(`Unknown message type: ${type}`);
    }
  } catch (error) {
    console.error('Message processing error:', error.message);
    throw error;
  }
};

// Database query handler
const handleDatabaseQuery = async (payload) => {
  const { query, params, operation } = payload;
  
  if (!query || typeof query !== 'string') {
    throw new Error('Invalid database query');
  }
  
  if (operation !== 'SELECT' && operation !== 'INSERT' && operation !== 'UPDATE' && operation !== 'DELETE') {
    throw new Error('Invalid database operation');
  }
  
  const client = await pool.connect();
  
  try {
    const result = await client.query(query, params);
    return { success: true, data: result.rows || result };
  } catch (error) {
    console.error('Database error:', error.message);
    throw error;
  } finally {
    client.release();
  }
};

// System command handler
const handleSystemCommand = async (payload) => {
  const { command, timeout = 5000 } = payload;
  
  if (!command || typeof command !== 'string') {
    throw new Error('Invalid system command');
  }
  
  // Sanitize command - only allow specific safe commands
  const allowedCommands = ['ls', 'pwd', 'date', 'echo'];
  const commandName = command.split(' ')[0];
  
  if (!allowedCommands.includes(commandName)) {
    throw new Error('Command not allowed');
  }
  
  try {
    const { stdout, stderr } = await execPromise(command, { timeout });
    return { success: true, output: stdout, error: stderr };
  } catch (error) {
    console.error('System command error:', error.message);
    throw error;
  }
};

// Data processing handler
const handleDataProcessing = async (payload) => {
  const { data, processor } = payload;
  
  if (!data || !Array.isArray(data)) {
    throw new Error('Invalid data format');
  }
  
  if (!processor || typeof processor !== 'string') {
    throw new Error('Processor function required');
  }
  
  // Validate processor function name
  const allowedProcessors = ['transform', 'validate', 'filter'];
  if (!allowedProcessors.includes(processor)) {
    throw new Error('Invalid processor function');
  }
  
  try {
    let result;
    
    switch (processor) {
      case 'transform':
        result = data.map(item => ({ ...item, processed: true }));
        break;
      case 'validate':
        result = data.filter(item => item && typeof item === 'object');
        break;
      case 'filter':
        result = data.filter(item => item.active === true);
        break;
      default:
        throw new Error('Processor not implemented');
    }
    
    return { success: true, data: result };
  } catch (error) {
    console.error('Data processing error:', error.message);
    throw error;
  }
};

// Message acknowledgment
const acknowledgeMessage = async (msg) => {
  try {
    await channel.ack(msg);
    console.log('Message acknowledged');
  } catch (error) {
    console.error('Acknowledge error:', error.message);
    throw error;
  }
};

// Error handling
const handleError = async (error, msg) => {
  console.error('Message processing failed:', error.message);
  
  try {
    // Reject message with requeue
    await channel.nack(msg, false, true);
  } catch (ackError) {
    console.error('Nack error:', ackError.message);
  }
};

// RabbitMQ consumer setup
const setupConsumer = async () => {
  try {
    connection = await amqp.connect(rabbitmqUrl);
    channel = await connection.createChannel();
    
    const queue = process.env.QUEUE_NAME || 'event_queue';
    await channel.assertQueue(queue, { durable: true });
    
    // Set up message consumer
    channel.prefetch(1);
    channel.consume(queue, async (msg) => {
      if (msg !== null) {
        try {
          await processMessage(msg);
          await acknowledgeMessage(msg);
        } catch (error) {
          await handleError(error, msg);
        }
      }
    }, { noAck: false });
    
    console.log('RabbitMQ consumer started');
  } catch (error) {
    console.error('RabbitMQ connection error:', error.message);
    process.exit(1);
  }
};

// Graceful shutdown
const shutdown = async () => {
  console.log('Shutting down...');
  
  try {
    if (channel) await channel.close();
    if (connection) await connection.close();
    await pool.end();
    process.exit(0);
  } catch (error) {
    console.error('Shutdown error:', error.message);
    process.exit(1);
  }
};

// Handle process signals
process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);

// Start the service
setupConsumer().catch(console.error);